#include <iostream>
#include <cstring>
#include <algorithm>
using namespace std;
string pluss(string a,string b,int c)
{
    int sum[505]={0}, a1[505]={0}, b1[505]={0};
    reverse(a.begin(),a.end());
    reverse(b.begin(),b.end());
    for(int i=0;i<=a.size()-1;i++)
    {
        if(a[i]>='0'&&a[i]<='9')
        {
            a1[i]=a[i]-48;
        }
        else
        {
            a1[i]=a[i]-'A'+10;
        }
    }
    for(int i=0;i<=b.size()-1;i++)
    {
        if(b[i]>='0'&&b[i]<='9')
        {
            b1[i]=b[i]-48;
        }
        else
        {
            b1[i]=b[i]-'A'+10;
        }
    }
    int len=max(a.size(),b.size());
    for(int i=0;i<=len-1;i++)
    {
        sum[i]=a1[i]+b1[i]+sum[i];
        sum[i+1]=sum[i]/c;
        sum[i]=sum[i]%c;
    }
    while(sum[len]==0&&len>0)
    {
        len--;
    }
    string sum1="";
    for(int i=len;i>=0;i--)
    {
        if(sum[i]>=10)
        {
            sum1+=(sum[i]-10+'A');
        }
        else
        {
            sum1+=(sum[i]+'0');
        }
    }
    return sum1;
}
int main()
{
    int b;
    cin>>b;
    string s1,s2;
    cin>>s1>>s2;
    cout<<pluss(s1,s2,b);
    return 0;
}
